 1→import { useEffect, useRef, useState } from 'react';
 2→
 3→export function useDebounce<T>(
 4→  value: T,
 5→  delay: number,
 6→): {
 7→  debouncedValue: T;
 8→  isPending: boolean;
 9→} {
10→  const [debouncedValue, setDebouncedValue] = useState(value);
11→  const [isPending, setIsPending] = useState(false);
12→  const previousValueRef = useRef(value);
13→
14→  useEffect(() => {
15→    if (Object.is(value, previousValueRef.current)) {
16→      return;
17→    }
18→    previousValueRef.current = value;
19→    setIsPending(true);
20→
21→    const timer = setTimeout(() => {
22→      setDebouncedValue(value);
23→      setIsPending(false);
24→    }, delay);
25→
26→    return () => {
27→      clearTimeout(timer);
28→    };
29→  }, [
30→    value,
31→    delay,
32→  ]);
33→
34→  return {
35→    debouncedValue,
36→    isPending,
37→  };
38→}
