  37→import './root_search_view.scss';
  38→
  39→const CYCLING_PLACEHOLDERS = [
  40→  'Type a command...',
  41→  'Search applications...',
  42→  'Calculate something...',
  43→  'Find files...',
  44→];
  45→
  46→function flattenItems(sections: SectionData[]): ListItemData[] {
  47→  return sections.flatMap(s => s.items);
  48→}
  49→
  50→function AppIcon({ src }: { src: string }) {
  51→  const [errored, setErrored] = useState(false);
  52→  if (errored) return <AppPlaceholderIcon />;
  53→  return (
  54→    <img
  55→      src={src}
  56→      alt=""
  57→      width={20}
  58→      height={20}
  59→      className="root-search__app-icon"
  60→      onError={() => setErrored(true)}
  61→    />
  62→  );
  63→}
  64→
  65→function AppPlaceholderIcon() {
  66→  return (
  67→    <svg width="20" height="20" viewBox="0 0 20 20" fill="none">
  68→      <rect width="20" height="20" rx="4" fill="currentColor" opacity="0.2" />
  69→      <path
  70→        d="M6 7L10 4L14 7V13L10 16L6 13V7Z"
  71→        stroke="currentColor"
  72→        strokeWidth="1.2"
  73→        strokeLinejoin="round"
  74→        opacity="0.5"
  75→      />
  76→    </svg>
  77→  );
  78→}
  79→
  80→const searchFilterSections: SearchDropdownSection[] = [
  81→  {
  82→    options: [
  83→      {
  84→        label: 'All',
  85→        value: 'all',
  86→      },
  87→    ],
  88→  },
  89→  {
  90→    title: 'Types',
  91→    options: [
  92→      {
  93→        label: 'Commands',
  94→        value: 'commands',
  95→      },
  96→      {
  97→        label: 'Applications',
  98→        value: 'applications',
  99→      },
 100→    ],
 101→  },
 102→];
