 104→interface RootSearchViewProps {
 105→  onCompactChange?: (compact: boolean) => void;
 106→  onLoadingChange?: (loading: boolean) => void;
 107→}
 108→
 109→export function RootSearchView({
 110→  onCompactChange,
 111→  onLoadingChange,
 112→}: RootSearchViewProps) {
 113→  const nav = useNavigation<NavViewData>();
 114→  const { push } = nav;
 115→
 116→  const [query, setQuery] = useState('');
 117→  const { debouncedValue: debouncedQuery, isPending: isSearchPending } =
 118→    useDebounce(query, 150);
 119→  const [filterValue, setFilterValue] = useState('all');
 120→  const [selectedIndex, setSelectedIndex] = useState(0);
 121→  const [actionsOpen, setActionsOpen] = useState(false);
 122→  const [quickLookOpen, setQuickLookOpen] = useState(false);
 123→
 124→  const { toasts, show: showToast, hide: hideToast } = useToast();
 125→  const { items: hudItems, show: showHUD } = useHUD();
 126→  const { alertState, confirmAlert, dismiss: dismissAlert } = useAlert();
 127→  const { favoriteIds, isFavorite, toggleFavorite, moveFavorite } =
 128→    useFavorites();
 129→  const { recentIds, addRecent } = useRecentCommands();
 130→  const { applications, refresh: refreshApps } = useApplications();
 131→
 132→  useEffect(() => {
 133→    if (nav.stackDepth === 0) {
 134→      setQuery('');
 135→      setFilterValue('all');
 136→      setSelectedIndex(0);
 137→      setActionsOpen(false);
 138→      setQuickLookOpen(false);
 139→    }
 140→  }, [nav.stackDepth]);
 141→
 142→  useEffect(() => {
 143→    if (!isTauri) return;
 144→    const platform = getPlatform();
 145→    let unsub: (() => void) | undefined;
 146→    let cancelled = false;
 147→
 148→    platform.window
 149→      .onFocusChanged(focused => {
 150→        if (focused) refreshApps();
 151→      })
 152→      .then(fn => {
 153→        if (cancelled) fn();
 154→        else unsub = fn;
 155→      });
 156→
 157→    return () => {
 158→      cancelled = true;
 159→      unsub?.();
 160→    };
 161→  }, [refreshApps]);
 162→
 163→  const appSection: SectionData | null = useMemo(() => {
 164→    if (applications.length === 0) return null;
 165→
 166→    const items: ListItemData[] = applications.map(app => ({
 167→      id: app.id,
 168→      title: app.name,
 169→      subtitle: 'Application',
 170→      icon: app.icon ? <AppIcon src={app.icon} /> : <AppPlaceholderIcon />,
 171→    }));
 172→
 173→    return {
 174→      title: 'Applications',
 175→      items,
 176→    };
 177→  }, [applications]);
 178→
 179→  const registrySections = useMemo(() => getSections(), []);
 180→
 181→  const allSections = useMemo(() => {
 182→    const sections = [...registrySections];
 183→    if (!appSection) return sections;
 184→
 185→    const existingIdx = sections.findIndex(s => s.title === 'Applications');
 186→    if (existingIdx >= 0) {
 187→      const existing = sections[existingIdx]!;
 188→      sections[existingIdx] = {
 189→        title: existing.title,
 190→        items: [
 191→          ...appSection.items,
 192→          ...existing.items,
 193→        ],
 194→      };
 195→    } else {
 196→      sections.push(appSection);
 197→    }
 198→    return sections;
 199→  }, [
 200→    registrySections,
 201→    appSection,
 202→  ]);
 203→
 204→  const filtered = useMemo(() => {
 205→    let sections = allSections;
 206→    if (filterValue === 'commands') {
 207→      sections = sections.filter(
 208→        s => s.title === 'Suggestions' || s.title === 'Commands',
 209→      );
 210→    } else if (filterValue === 'applications') {
 211→      sections = sections.filter(s => s.title === 'Applications');
 212→    }
 213→
 214→    let filteredResult: SectionData[];
 215→    if (debouncedQuery) {
 216→      const commandResults = searchCommands(debouncedQuery);
 217→      const appItems = appSection?.items ?? [];
 218→      const matchedApps = appItems
 219→        .map(item => ({
 220→          item,
 221→          score: fuzzyScore(debouncedQuery, item.title)?.score ?? -Infinity,
 222→        }))
 223→        .filter(({ score }) => score > -Infinity)
 224→        .sort((a, b) => b.score - a.score)
 225→        .map(({ item }) => item);
 226→
 227→      const mergedSections = [...commandResults];
 228→      if (matchedApps.length > 0) {
 229→        const appSectionIdx = mergedSections.findIndex(
 230→          s => s.title === 'Applications',
 231→        );
 232→        if (appSectionIdx >= 0) {
 233→          const existing = mergedSections[appSectionIdx]!;
 234→          const existingIds = new Set(existing.items.map(i => i.id));
 235→          const newApps = matchedApps.filter(a => !existingIds.has(a.id));
 236→          mergedSections[appSectionIdx] = {
 237→            title: existing.title,
 238→            items: [
 239→              ...newApps,
 240→              ...existing.items,
 241→            ],
 242→          };
 243→        } else {
 244→          mergedSections.push({
 245→            title: 'Applications',
 246→            items: matchedApps,
 247→          });
 248→        }
 249→      }
 250→
 251→      filteredResult = mergedSections
 252→        .map(s => {
 253→          if (filterValue === 'commands') {
 254→            return s.title === 'Suggestions' || s.title === 'Commands'
 255→              ? s
 256→              : {
 257→                  ...s,
 258→                  items: [],
 259→                };
 260→          }
 261→          if (filterValue === 'applications') {
 262→            return s.title === 'Applications'
 263→              ? s
 264→              : {
 265→                  ...s,
 266→                  items: [],
 267→                };
 268→          }
 269→          return s;
 270→        })
 271→        .filter(s => s.items.length > 0);
 272→    } else {
 273→      filteredResult = sections;
 274→    }
 275→
 276→    const allFlatItems = allSections.flatMap(s => s.items);
 277→    const favoriteItems = favoriteIds
 278→      .map(id => allFlatItems.find(item => item.id === id))
 279→      .filter((item): item is ListItemData => !!item);
 280→
 281→    if (debouncedQuery) {
 282→      const filteredFavs = favoriteItems.filter(
 283→        item =>
 284→          fuzzyMatch(debouncedQuery, item.title) ||
 285→          fuzzyMatch(debouncedQuery, item.subtitle ?? ''),
 286→      );
 287→      if (filteredFavs.length > 0) {
 288→        const favIds = new Set(filteredFavs.map(f => f.id));
 289→        const dedupedSections = filteredResult
 290→          .map(s => ({
 291→            ...s,
 292→            items: s.items.filter(item => !favIds.has(item.id)),
 293→          }))
 294→          .filter(s => s.items.length > 0);
 295→        return [
 296→          {
 297→            title: 'Favorites',
 298→            items: filteredFavs,
 299→          },
 300→          ...dedupedSections,
 301→        ];
 302→      }
 303→      return filteredResult;
 304→    }
 305→
 306→    const pinnedSections: SectionData[] = [];
 307→    const dedupIds = new Set<string>();
 308→
 309→    if (favoriteItems.length > 0) {
 310→      pinnedSections.push({
 311→        title: 'Favorites',
 312→        items: favoriteItems,
 313→      });
 314→      for (const item of favoriteItems) {
 315→        dedupIds.add(item.id);
 316→      }
 317→    }
 318→
 319→    const favSet = new Set(favoriteIds);
 320→    const recentItems = recentIds
 321→      .filter(id => !favSet.has(id))
 322→      .map(id => allFlatItems.find(item => item.id === id))
 323→      .filter((item): item is ListItemData => !!item);
 324→
 325→    if (recentItems.length > 0) {
 326→      pinnedSections.push({
 327→        title: 'Recent Commands',
 328→        items: recentItems,
 329→      });
 330→      for (const item of recentItems) {
 331→        dedupIds.add(item.id);
 332→      }
 333→    }
 334→
 335→    if (pinnedSections.length > 0) {
 336→      const dedupedSections = filteredResult
 337→        .map(s => ({
 338→          ...s,
 339→          items: s.items.filter(item => !dedupIds.has(item.id)),
 340→        }))
 341→        .filter(s => s.items.length > 0);
 342→      return [
 343→        ...pinnedSections,
 344→        ...dedupedSections,
 345→      ];
 346→    }
 347→
 348→    return filteredResult;
 349→  }, [
 350→    debouncedQuery,
 351→    filterValue,
 352→    favoriteIds,
 353→    recentIds,
 354→    allSections,
 355→    appSection,
 356→  ]);
 357→
 358→  const calculatorResult = useMemo(() => {
 359→    if (!debouncedQuery.trim()) return null;
 360→    return evaluate(debouncedQuery);
 361→  }, [debouncedQuery]);
 362→
 363→  const allItems = useMemo(() => {
 364→    const items = flattenItems(filtered);
 365→    if (calculatorResult) {
 366→      const calcItem: ListItemData = {
 367→        id: '__calculator__',
 368→        title: `= ${calculatorResult}`,
 369→        subtitle: debouncedQuery.trim(),
 370→        icon: <CalculatorIcon />,
 371→      };
 372→      return [
 373→        calcItem,
 374→        ...items,
 375→      ];
 376→    }
 377→    return items;
 378→  }, [
 379→    filtered,
 380→    calculatorResult,
 381→    debouncedQuery,
 382→  ]);
 383→
 384→  const appPathMap = useMemo(() => {
 385→    const map = new Map<string, string>();
 386→    for (const app of applications) {
 387→      map.set(app.id, app.path);
 388→    }
 389→    return map;
 390→  }, [applications]);
 391→
 392→  const selectedItem = allItems[selectedIndex];
 393→
 394→  const handleQueryChange = useCallback((value: string) => {
 395→    setQuery(value);
 396→    setSelectedIndex(0);
 397→    setActionsOpen(false);
 398→  }, []);
 399→
 400→  const handleFilterChange = useCallback((value: string) => {
 401→    setFilterValue(value);
 402→    setSelectedIndex(0);
 403→  }, []);
 404→
 405→  const handleActiveIndexChange = useCallback((index: number) => {
 406→    setSelectedIndex(index);
 407→    setActionsOpen(false);
 408→  }, []);
 409→
 410→  const handleDrillIn = useCallback(() => {
 411→    const item = allItems[selectedIndex];
 412→    if (!item) return;
 413→
 414→    setActionsOpen(false);
 415→
 416→    if (item.id === '__calculator__' && calculatorResult) {
 417→      performCopy(calculatorResult, showHUD, {
 418→        hudIcon: <ClipboardHUDIcon />,
 419→        hudTitle: `Copied ${calculatorResult}`,
 420→      });
 421→      return;
 422→    }
 423→
 424→    const appPath = appPathMap.get(item.id);
 425→    if (appPath) {
 426→      getPlatform()
 427→        .apps.launchApplication(appPath)
 428→        .then(() => {
 429→          if (isTauri) {
 430→            getPlatform().window.hide();
 431→          }
 432→        })
 433→        .catch(() => {
 434→          showToast({
 435→            style: 'error',
 436→            title: `Failed to launch ${item.title}`,
 437→          });
 438→        });
 439→      return;
 440→    }
 441→
 442→    const cmd = getCommand(item.id);
 443→
 444→    if (cmd?.component) {
 445→      addRecent(item.id);
 446→      push(cmd.name, {
 447→        type: 'command',
 448→        commandId: cmd.id,
 449→      });
 450→      setQuery('');
 451→      setSelectedIndex(0);
 452→    } else if (item.detail) {
 453→      push(item.title, {
 454→        type: 'detail',
 455→        item,
 456→      });
 457→      setQuery('');
 458→      showToast({
 459→        style: 'success',
 460→        title: `Opened ${item.title}`,
 461→      });
 462→    } else {
 463→      showToast({
 464→        style: 'success',
 465→        title: `Opened ${item.title}`,
 466→      });
 467→    }
 468→  }, [
 469→    allItems,
 470→    selectedIndex,
 471→    showToast,
 472→    showHUD,
 473→    calculatorResult,
 474→    push,
 475→    addRecent,
 476→    appPathMap,
 477→  ]);
 478→
 479→  const toggleActions = useCallback(() => {
 480→    setActionsOpen(prev => !prev);
 481→  }, []);
 482→
 483→  const closeActions = useCallback(() => {
 484→    setActionsOpen(false);
 485→  }, []);
 486→
 487→  useKeyboardShortcut(
 488→    {
 489→      key: 'k',
 490→      meta: true,
 491→    },
 492→    toggleActions,
 493→  );
 494→
 495→  const handleToggleFavorite = useCallback(() => {
 496→    if (!selectedItem || selectedItem.id === '__calculator__') {
 497→      return;
 498→    }
 499→    const wasAlreadyFavorite = isFavorite(selectedItem.id);
 500→    toggleFavorite(selectedItem.id);
 501→    showHUD({
 502→      icon: <StarFilledIcon />,
 503→      title: wasAlreadyFavorite
 504→        ? 'Removed from Favorites'
 505→        : 'Added to Favorites',
 506→    });
 507→  }, [
 508→    selectedItem,
 509→    toggleFavorite,
 510→    isFavorite,
 511→    showHUD,
 512→  ]);
 513→
 514→  useKeyboardShortcut(
 515→    {
 516→      key: 'f',
 517→      meta: true,
 518→      shift: true,
 519→    },
 520→    handleToggleFavorite,
 521→    { enabled: !!selectedItem },
 522→  );
 523→
 524→  const handleCopyValue = useCallback(() => {
 525→    if (!selectedItem) return;
 526→    setActionsOpen(false);
 527→    if (selectedItem.id === '__calculator__' && calculatorResult) {
 528→      performCopy(calculatorResult, showHUD, {
 529→        hudIcon: <ClipboardHUDIcon />,
 530→        hudTitle: `Copied ${calculatorResult}`,
 531→      });
 532→      return;
 533→    }
 534→    performCopy(selectedItem.title, showHUD);
 535→  }, [
 536→    selectedItem,
 537→    calculatorResult,
 538→    showHUD,
 539→  ]);
 540→
 541→  useKeyboardShortcut(
 542→    {
 543→      key: 'l',
 544→      meta: true,
 545→    },
 546→    handleCopyValue,
 547→    { enabled: !!selectedItem },
 548→  );
 549→
 550→  const handleMoveFavoriteUp = useCallback(() => {
 551→    if (!selectedItem || !isFavorite(selectedItem.id)) return;
 552→    moveFavorite(selectedItem.id, 'up');
 553→    setSelectedIndex(prev => Math.max(0, prev - 1));
 554→  }, [
 555→    selectedItem,
 556→    isFavorite,
 557→    moveFavorite,
 558→  ]);
 559→
 560→  const handleMoveFavoriteDown = useCallback(() => {
 561→    if (!selectedItem || !isFavorite(selectedItem.id)) return;
 562→    moveFavorite(selectedItem.id, 'down');
 563→    setSelectedIndex(prev => prev + 1);
 564→  }, [
 565→    selectedItem,
 566→    isFavorite,
 567→    moveFavorite,
 568→  ]);
 569→
 570→  useKeyboardShortcut(
 571→    {
 572→      key: 'ArrowUp',
 573→      meta: true,
 574→      alt: true,
 575→    },
 576→    handleMoveFavoriteUp,
 577→    {
 578→      enabled: !!selectedItem && isFavorite(selectedItem.id),
 579→    },
 580→  );
 581→
 582→  useKeyboardShortcut(
 583→    {
 584→      key: 'ArrowDown',
 585→      meta: true,
 586→      alt: true,
 587→    },
 588→    handleMoveFavoriteDown,
 589→    {
 590→      enabled: !!selectedItem && isFavorite(selectedItem.id),
 591→    },
 592→  );
 593→
 594→  const openSettings = useCallback(() => {
 595→    const settingsCmd = getCommand('settings');
 596→    if (settingsCmd) {
 597→      push('Settings', {
 598→        type: 'command',
 599→        commandId: 'settings',
 600→      });
 601→      setQuery('');
 602→      setSelectedIndex(0);
 603→      setActionsOpen(false);
 604→    }
 605→  }, [push]);
 606→
 607→  useKeyboardShortcut(
 608→    {
 609→      key: ',',
 610→      meta: true,
 611→    },
 612→    openSettings,
 613→  );
 614→
 615→  const toggleQuickLook = useCallback(() => {
 616→    setQuickLookOpen(prev => !prev);
 617→  }, []);
 618→
 619→  const closeQuickLook = useCallback(() => {
 620→    setQuickLookOpen(false);
 621→  }, []);
 622→
 623→  useKeyboardShortcut(
 624→    {
 625→      key: 'y',
 626→      meta: true,
 627→    },
 628→    toggleQuickLook,
 629→    { enabled: !!selectedItem?.detail },
 630→  );
 631→
 632→  useEffect(() => {
 633→    if (!selectedItem?.detail) return;
 634→
 635→    function handleSpaceBar(e: KeyboardEvent) {
 636→      if (e.key !== ' ' || e.metaKey || e.ctrlKey || e.altKey) {
 637→        return;
 638→      }
 639→      if (query !== '') return;
 640→
 641→      e.preventDefault();
 642→      e.stopPropagation();
 643→      setQuickLookOpen(prev => !prev);
 644→    }
 645→
 646→    window.addEventListener('keydown', handleSpaceBar);
 647→    return () => window.removeEventListener('keydown', handleSpaceBar);
 648→  }, [
 649→    selectedItem?.detail,
 650→    query,
 651→  ]);
 652→
 653→  const isCalculatorSelected = selectedItem?.id === '__calculator__';
 654→  const detail = isCalculatorSelected ? undefined : selectedItem?.detail;
 655→
 656→  const dropdownSections = useMemo(
 657→    () => [
 658→      {
 659→        title: 'Primary Actions',
 660→        actions: [
 661→          isCalculatorSelected && calculatorResult
 662→            ? createCopyAction(
 663→                {
 664→                  content: calculatorResult,
 665→                  title: 'Copy Result',
 666→                  shortcut: <Kbd keys={['↵']} />,
 667→                  hudIcon: <ClipboardHUDIcon />,
 668→                  hudTitle: `Copied ${calculatorResult}`,
 669→                },
 670→                showHUD,
 671→              )
 672→            : {
 673→                label: 'Open',
 674→                shortcut: <Kbd keys={['↵']} />,
 675→                onClick: () => {
 676→                  if (selectedItem) {
 677→                    showToast({
 678→                      style: 'success' as const,
 679→                      title: `Opened ${selectedItem.title}`,
 680→                    });
 681→                  }
 682→                },
 683→              },
 684→          {
 685→            label: 'Quick Look',
 686→            shortcut: (
 687→              <Kbd
 688→                keys={[
 689→                  '⌘',
 690→                  'Y',
 691→                ]}
 692→              />
 693→            ),
 694→            onClick: () => {
 695→              if (selectedItem?.detail) {
 696→                setActionsOpen(false);
 697→                setQuickLookOpen(prev => !prev);
 698→              }
 699→            },
 700→          },
 701→          ...(!isCalculatorSelected && selectedItem
 702→            ? [
