316→        breadcrumbs={nav.breadcrumbs.length > 0 ? nav.breadcrumbs : undefined}
317→        dropdown={
318→          <SearchDropdown
319→            sections={FILTER_SECTIONS}
320→            value={filterValue}
321→            onChange={handleFilterChange}
322→          />
323→        }
324→      />
325→      <LoadingBar visible={isSearchPending} />
326→      <div className="command-palette__body">
327→        <div className="command-palette__list-container">
328→          {totalItemCount === 0 ? (
