333→            />
334→          ) : (
335→            <List
336→              itemCount={totalItemCount}
337→              onActiveIndexChange={handleActiveIndexChange}
338→              onAction={handleApply}
339→            >
340→              {(() => {
341→                let globalIndex = 0;
342→                return groupedByCategory.map(group => (
343→                  <ListSection
344→                    key={group.category}
345→                    title={CATEGORY_LABELS[group.category]}
346→                  >
