 19→function renderNavView(data: NavViewData) {
 20→  if (data.type === 'command') {
 21→    const cmd = getCommand(data.commandId);
 22→    if (cmd?.component) {
 23→      const Component = cmd.component;
 24→      return <Component />;
 25→    }
 26→    return null;
 27→  }
 28→
 29→  if (data.type === 'detail') {
 30→    return <DetailItemView item={data.item} />;
 31→  }
 32→
 33→  return null;
 34→}
 35→
 36→export function App() {
 37→  useTheme();
 38→  const nav = useNavigationStack<NavViewData>('Raycast');
 39→  const { push, popToRoot } = nav;
 40→  const { addRecent } = useRecentCommands();
 41→  const [isCompact, setIsCompact] = useState(true);
 42→  const [isLoading, setIsLoading] = useState(false);
 43→  const [rootResetKey, setRootResetKey] = useState(0);
 44→
 45→  const handleTrayNavigate = useCallback(
 46→    (target: string) => {
 47→      const mapping = TRAY_COMMAND_MAP[target];
 48→      if (!mapping) return;
 49→
 50→      const cmd = getCommand(mapping.id);
 51→      if (!cmd?.component) return;
 52→
 53→      popToRoot();
 54→      addRecent(mapping.id);
 55→      push(mapping.name, {
 56→        type: 'command',
 57→        commandId: mapping.id,
 58→      });
 59→    },
 60→    [
 61→      push,
 62→      popToRoot,
 63→      addRecent,
 64→    ],
 65→  );
 66→
 67→  useWindow({
 68→    onShow: () => {
 69→      const input =
 70→        document.querySelector<HTMLInputElement>('.search-bar__input');
 71→      input?.focus();
 72→    },
 73→    onHide: () => {
 74→      popToRoot();
 75→      setRootResetKey(k => k + 1);
 76→    },
 77→    onTrayNavigate: handleTrayNavigate,
 78→  });
 79→
 80→  const currentNavData = nav.currentEntry?.data;
 81→  const isFullView =
 82→    currentNavData?.type === 'command' &&
 83→    (getCommand(currentNavData.commandId)?.fullView ?? false);
 84→
 85→  const navDirectionClass =
 86→    nav.direction === 'push'
 87→      ? ' command-palette__nav-view--push'
 88→      : nav.direction === 'pop'
 89→        ? ' command-palette__nav-view--pop'
 90→        : '';
 91→
 92→  const isRoot = !currentNavData;
 93→  const compact = isRoot && isCompact;
 94→
 95→  const contextLabel =
 96→    nav.breadcrumbs.length > 0
 97→      ? nav.breadcrumbs[nav.breadcrumbs.length - 1]!.label
 98→      : 'Raycast';
 99→
100→  return (
101→    <NavigationContextProvider value={nav}>
102→      <CommandPalette isLoading={isLoading} compact={compact}>
103→        {isFullView && nav.currentEntry ? (
104→          <ErrorBoundary key={nav.navKey} onReset={nav.pop}>
105→            <div className={`command-palette__nav-view${navDirectionClass}`}>
106→              {renderNavView(nav.currentEntry.data)}
107→            </div>
108→          </ErrorBoundary>
109→        ) : nav.currentEntry ? (
110→          <>
111→            <SearchBar
112→              value=""
113→              onChange={() => {}}
114→              breadcrumbs={
115→                nav.breadcrumbs.length > 0 ? nav.breadcrumbs : undefined
116→              }
117→            />
118→            <ErrorBoundary key={nav.navKey} onReset={nav.pop}>
119→              <div className={`command-palette__nav-view${navDirectionClass}`}>
120→                <div className="command-palette__body">
121→                  <div className="command-palette__list-container">
122→                    {renderNavView(nav.currentEntry.data)}
123→                  </div>
124→                </div>
125→              </div>
126→            </ErrorBoundary>
127→            <ActionPanel
128→              contextLabel={contextLabel}
129→              actions={[
130→                {
131→                  label: 'Open',
132→                  shortcut: <Kbd keys={['↵']} />,
133→                },
134→              ]}
135→              dropdownOpen={false}
136→              dropdownSections={[]}
137→              onDropdownClose={() => {}}
138→            />
139→          </>
140→        ) : (
141→          <RootSearchView
142→            key={rootResetKey}
143→            onCompactChange={setIsCompact}
144→            onLoadingChange={setIsLoading}
145→          />
146→        )}
147→      </CommandPalette>
148→    </NavigationContextProvider>
149→  );
150→}
